/**
 * seed-hierarchy.mjs
 *
 * Seeds the Okanagan College org hierarchy from the pre-processed
 * hierarchy_analysis.json (generated by analyze_hierarchy.py).
 *
 * What it creates:
 *   1. organizational_units — Okanagan College root + 4 schools + 37 departments
 *   2. auth.users + profiles — for every person in the CSV files
 *   3. org_unit_members — VP / AD / dept_head / admin memberships
 *
 * Run from the project root:
 *   node scripts/seed-hierarchy.mjs
 *
 * Idempotent: safe to re-run. Skips existing auth users; upserts everything else.
 */

import { existsSync, readFileSync } from "node:fs";
import { createClient } from "@supabase/supabase-js";

// ── env ───────────────────────────────────────────────────────────────────────

loadEnvFiles([".env.local", ".env.development", "apps/web/.env.local"]);

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const serviceRoleKey = process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!supabaseUrl || !serviceRoleKey) {
  console.error(
    "Missing env: NEXT_PUBLIC_SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY must be set."
  );
  process.exit(1);
}

const supabase = createClient(supabaseUrl, serviceRoleKey, {
  auth: { autoRefreshToken: false, persistSession: false },
});

// ── load analysis ─────────────────────────────────────────────────────────────

const analysisPath = new URL("./hierarchy_analysis.json", import.meta.url);
const analysis = JSON.parse(readFileSync(analysisPath, "utf8"));

const { admin_full, admin_viewer, vps, ads, chairs, schools, departments } = analysis;

// ── helpers ───────────────────────────────────────────────────────────────────

function log(msg) {
  process.stdout.write(msg + "\n");
}

async function upsertProfile(userId, email, fullName, role) {
  const { error } = await supabase.from("profiles").upsert(
    { id: userId, email, full_name: fullName, role },
    { onConflict: "id" }
  );
  if (error) throw new Error(`Profile upsert failed for ${email}: ${error.message}`);
}

async function ensureAuthUser(email, fullName, role) {
  // Check if the auth user already exists via a profile lookup by email
  const { data: existing } = await supabase
    .from("profiles")
    .select("id")
    .eq("email", email)
    .maybeSingle();

  if (existing) {
    // Update role + full_name in case they changed
    const { error } = await supabase
      .from("profiles")
      .update({ full_name: fullName, role })
      .eq("id", existing.id);
    if (error) throw new Error(`Profile update failed for ${email}: ${error.message}`);
    return existing.id;
  }

  // Create new auth user — trigger auto-creates the profile row
  const { data, error } = await supabase.auth.admin.createUser({
    email,
    password: "OkanaganDev2026!",
    email_confirm: true,
    user_metadata: { full_name: fullName },
  });

  if (error) {
    if (error.message.includes("already been registered")) {
      // Race or duplicate — fetch via admin list
      const { data: list } = await supabase.auth.admin.listUsers();
      const match = list?.users?.find((u) => u.email === email);
      if (match) {
        await upsertProfile(match.id, email, fullName, role);
        return match.id;
      }
    }
    throw new Error(`Auth user creation failed for ${email}: ${error.message}`);
  }

  const userId = data.user.id;
  await upsertProfile(userId, email, fullName, role);
  return userId;
}

// ── step 1: build org unit tree ───────────────────────────────────────────────

log("\n=== Step 1: Org Units ===");

// Root institution — parent_id is NULL so we can't rely on the composite unique constraint;
// use select-or-insert to stay idempotent.
let rootId;
{
  const { data: existing } = await supabase
    .from("organizational_units")
    .select("id")
    .eq("name", "Okanagan College")
    .is("parent_id", null)
    .maybeSingle();

  if (existing) {
    rootId = existing.id;
  } else {
    const { data, error } = await supabase
      .from("organizational_units")
      .insert({ name: "Okanagan College", type: "college" })
      .select("id")
      .single();
    if (error) throw new Error("Root unit insert failed: " + error.message);
    rootId = data.id;
  }
}
log(`  root: Okanagan College (${rootId})`);

// Schools
const schoolIdMap = {}; // school name → uuid

for (const school of schools) {
  const { data, error } = await supabase
    .from("organizational_units")
    .upsert({ name: school, type: "school", parent_id: rootId }, { onConflict: "name,parent_id" })
    .select("id");
  if (error) throw new Error(`School upsert failed (${school}): ${error.message}`);
  schoolIdMap[school] = data[0].id;
  log(`  school: ${school} (${data[0].id})`);
}

// Departments — [name, school_name] tuples
const deptIdMap = {}; // "dept|school" → uuid

for (const [deptName, schoolName] of departments) {
  const parentId = schoolIdMap[schoolName];
  if (!parentId) {
    log(`  WARN: no school found for dept "${deptName}" → school "${schoolName}", skipping`);
    continue;
  }
  const key = `${deptName}|${schoolName}`;
  const { data, error } = await supabase
    .from("organizational_units")
    .upsert(
      { name: deptName, type: "department", parent_id: parentId },
      { onConflict: "name,parent_id" }
    )
    .select("id");
  if (error) throw new Error(`Dept upsert failed (${deptName}): ${error.message}`);
  deptIdMap[key] = data[0].id;
}
log(`  departments created/updated: ${Object.keys(deptIdMap).length}`);

// ── step 2: create users ──────────────────────────────────────────────────────

log("\n=== Step 2: Auth Users + Profiles ===");

// Collect all unique users — email is the unique key
const allUsers = new Map(); // email → { fullName, role }

for (const u of admin_full)   allUsers.set(u.email, { fullName: u.full_name, role: "admin_full" });
for (const u of admin_viewer) allUsers.set(u.email, { fullName: u.full_name, role: "admin_viewer" });
for (const u of vps)          allUsers.set(u.email, { fullName: u.full_name, role: "standard_user" });
for (const u of ads)          allUsers.set(u.email, { fullName: u.full_name, role: "standard_user" });
for (const u of chairs)       allUsers.set(u.email, { fullName: u.full_name, role: "standard_user" });

log(`  total unique users: ${allUsers.size}`);

const profileIdMap = {}; // email → uuid

let created = 0;
for (const [email, { fullName, role }] of allUsers) {
  try {
    const id = await ensureAuthUser(email, fullName, role);
    profileIdMap[email] = id;
    created++;
    if (created % 10 === 0) log(`  ... ${created}/${allUsers.size} users processed`);
  } catch (err) {
    log(`  ERROR: ${err.message}`);
  }
}
log(`  done: ${created} users processed`);

// ── step 3: org unit memberships ─────────────────────────────────────────────

log("\n=== Step 3: Org Unit Members ===");

const memberRows = [];

// VPs → their school
for (const vp of vps) {
  const profileId = profileIdMap[vp.email];
  const orgUnitId = schoolIdMap[vp.school];
  if (!profileId || !orgUnitId) {
    log(`  WARN: skipping VP ${vp.email} — missing profile or school`);
    continue;
  }
  memberRows.push({ profile_id: profileId, org_unit_id: orgUnitId, title: "vp", is_primary: true });
}

// ADs → their school
for (const ad of ads) {
  const profileId = profileIdMap[ad.email];
  const orgUnitId = schoolIdMap[ad.school];
  if (!profileId || !orgUnitId) {
    log(`  WARN: skipping AD ${ad.email} — missing profile or school`);
    continue;
  }
  memberRows.push({ profile_id: profileId, org_unit_id: orgUnitId, title: "associate_dean", is_primary: true });
}

// Admin users → root institution (so they can see everything)
for (const u of [...admin_full, ...admin_viewer]) {
  const profileId = profileIdMap[u.email];
  if (!profileId) continue;
  memberRows.push({ profile_id: profileId, org_unit_id: rootId, title: "admin", is_primary: true });
}

// Chairs → their department unit (one row per AD they report to means one dept per chair)
// A chair may report to multiple ADs within the same school — we add them to the dept unit once.
const addedChairDept = new Set(); // "email|deptKey" dedup

for (const chair of chairs) {
  const profileId = profileIdMap[chair.email];
  if (!profileId) continue;

  // Find the correct department unit
  // chair.supervisor_ad_emails tells us which ADs they report to — use those to resolve the school
  for (const adEmail of chair.supervisor_ad_emails) {
    const ad = ads.find((a) => a.email === adEmail);
    if (!ad) continue;

    const deptKey = `${chair.dept}|${ad.school}`;
    const orgUnitId = deptIdMap[deptKey];
    if (!orgUnitId) continue;

    const dedupeKey = `${chair.email}|${deptKey}`;
    if (addedChairDept.has(dedupeKey)) continue;
    addedChairDept.add(dedupeKey);

    memberRows.push({
      profile_id: profileId,
      org_unit_id: orgUnitId,
      title: "dept_head",
      is_primary: true,
    });
    break; // one membership per department is enough — cross-school will add a second row
  }

  // Cross-school case: if chair reports to ADs in different schools, add a second membership
  const schoolsForChair = [...new Set(
    chair.supervisor_ad_emails
      .map((e) => ads.find((a) => a.email === e)?.school)
      .filter(Boolean)
  )];

  if (schoolsForChair.length > 1) {
    for (const school of schoolsForChair.slice(1)) {
      const deptKey = `${chair.dept}|${school}`;
      const orgUnitId = deptIdMap[deptKey];
      if (!orgUnitId) continue;
      const dedupeKey = `${chair.email}|${deptKey}`;
      if (addedChairDept.has(dedupeKey)) continue;
      addedChairDept.add(dedupeKey);
      memberRows.push({
        profile_id: profileId,
        org_unit_id: orgUnitId,
        title: "dept_head",
        is_primary: false, // secondary school assignment
      });
    }
  }
}

log(`  total membership rows to insert: ${memberRows.length}`);

if (memberRows.length > 0) {
  const { error } = await supabase
    .from("org_unit_members")
    .upsert(memberRows, { onConflict: "profile_id,org_unit_id" });
  if (error) throw new Error("org_unit_members upsert failed: " + error.message);
}

log(`  done`);

// ── summary ───────────────────────────────────────────────────────────────────

log("\n=== Done ===");
log(`  Org units:   1 college + ${schools.length} schools + ${Object.keys(deptIdMap).length} departments`);
log(`  Profiles:    ${created} created/updated`);
log(`  Memberships: ${memberRows.length} rows`);
log("");

// ── env loader ────────────────────────────────────────────────────────────────

function loadEnvFiles(files) {
  for (const file of files) {
    if (!existsSync(file)) continue;
    const lines = readFileSync(file, "utf8").split(/\r?\n/);
    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed || trimmed.startsWith("#")) continue;
      const eq = trimmed.indexOf("=");
      if (eq === -1) continue;
      const key = trimmed.slice(0, eq).trim();
      const val = trimmed.slice(eq + 1).trim().replace(/^["']|["']$/g, "");
      if (!process.env[key]) process.env[key] = val;
    }
  }
}
